const restaurants = [
  { name: 'The Commons Thonglor', rating: 4.6, reviews: 3248, price: 300, btsM: 350, group: true },
  { name: 'Ekkamai 63 Street Food', rating: 4.2, reviews: 1240, price: 170, btsM: 200, group: true },
  { name: 'The Never Ending Summer', rating: 4.7, reviews: 1624, price: 500, btsM: 800, group: true },
  { name: 'Meatlicious BBQ', rating: 4.3, reviews: 852, price: 425, btsM: 400, group: true },
  { name: 'Grease Restaurant & Bar', rating: 4.1, reviews: 1463, price: 375, btsM: 500, group: true }
];
const scored = restaurants.map((r,i) => {
  const s1 = Math.round(Math.min(25, (r.rating/5)*15 + Math.min(10, r.reviews/100))*10)/10;
  const s2 = r.group ? 20 : 5;
  const s3 = r.price<=300?15:r.price<=500?12:8;
  const s4 = r.btsM<=500?15:r.btsM<=1000?10:5;
  const s5 = 15;
  const s6 = [9,6,9,6,5][i];
  const total = Math.round((s1+s2+s3+s4+s5+s6)*10)/10;
  return { rank: i+1, restaurantName: r.name, totalScore: total, scoredAt: new Date().toISOString() };
}).sort((a,b)=>b.totalScore-a.totalScore).map((r,i)=>({...r,rank:i+1}));
return [{ json: { results: scored, top1: scored[0].restaurantName, top1Score: scored[0].totalScore, message: 'Scoring completed by n8n automation' } }];

